import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { useAppContext } from '../context/AppContext';
import { sendChatMessage } from '../api';

const initialBotMessage = {
  id: 'welcome',
  role: 'bot',
  text: 'Ask me anything about Indian cattle breeds.',
};

export default function Chat() {
  const { activeChat, addChat } = useAppContext();
  const [messages, setMessages] = useState([initialBotMessage]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (activeChat?.messages?.length) {
      setMessages(activeChat.messages);
      setInput('');
      setError('');
    }
  }, [activeChat]);

  const handleSend = async () => {
    const trimmed = input.trim();
    if (!trimmed) return;

    const nextMessages = [...messages, { id: `user-${Date.now()}`, role: 'user', text: trimmed }];
    setMessages(nextMessages);
    setInput('');
    setLoading(true);
    setError('');

    try {
      const response = await sendChatMessage(trimmed);
      const updated = [...nextMessages, { id: `bot-${Date.now()}`, role: 'bot', text: response }];
      setMessages(updated);
      addChat({ title: trimmed, messages: updated });
    } catch (err) {
      setError(err.message);
      setMessages((prev) => [...prev, { id: `bot-fail-${Date.now()}`, role: 'bot', text: 'Unable to fetch a response. Please try again.' }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="chat-page">
      <div className="panel-header">
        <p className="panel-label">Cattle assistant</p>
        <h2>Chat with the breed expert</h2>
      </div>

      <div className="chat-shell">
        <div className="chat-messages">
          {messages.map((item) => (
            <motion.div
              key={item.id}
              className={`chat-bubble ${item.role}`}
              initial={{ opacity: 0, y: 16 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.24 }}
            >
              <p>{item.text}</p>
            </motion.div>
          ))}
        </div>

        {error && <div className="field-error">{error}</div>}

        <div className="chat-input-row">
          <input
            type="text"
            value={input}
            onChange={(event) => setInput(event.target.value)}
            onKeyDown={(event) => event.key === 'Enter' && !loading && handleSend()}
            placeholder="Ask a breed question..."
            disabled={loading}
          />
          <button type="button" className="primary-button" onClick={handleSend} disabled={loading || !input.trim()}>
            Send
          </button>
        </div>
      </div>
    </div>
  );
}
